UPDATE `product_i18n` SET `description` = 'AVAR; Cucurbita maxima × Cucurbita moschata hibriti bir anaç çeşididir. Özellikle karpuz, kavun ve hıyar yetiştiriciliğinde güçlü ve güvenilir bir kök anaç olarak kullanılır. Güçlü kök yapısı, yüksek dirençli kök sistemi ve Fon 0,1 toleransı sayesinde aşılı üretimde güvenilir performans sunar.', `meta_description` = 'AVAR anaç; Cucurbita maxima × Cucurbita moschata hibriti, güçlü kök yapısı ve Fon 0,1 toleransı ile karpuz, kavun ve hıyar için uygundur.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000001' AND `locale` = 'tr';
UPDATE `product_i18n` SET `description` = 'AVAR is a Cucurbita maxima × Cucurbita moschata hybrid rootstock. It is used as a strong and reliable rootstock especially in watermelon, melon and cucumber cultivation. Its vigorous root system, highly resilient roots and Fusarium oxysporum f. sp. niveum race 0,1 tolerance provide dependable performance in grafted production.', `meta_description` = 'AVAR rootstock is a Cucurbita maxima × Cucurbita moschata hybrid with strong roots and Fon 0,1 tolerance for watermelon, melon and cucumber.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000001' AND `locale` = 'en';
UPDATE `product_i18n` SET `description` = 'AVAR ist eine Unterlagensorte als Hybrid aus Cucurbita maxima × Cucurbita moschata. Sie wird besonders im Anbau von Wassermelone, Melone und Gurke als starke und zuverlässige Unterlage eingesetzt. Das kräftige Wurzelsystem, die widerstandsfähigen Wurzeln und die Fon-0,1-Toleranz sorgen für eine verlässliche Leistung in der veredelten Produktion.', `meta_description` = 'AVAR ist eine Unterlage aus Cucurbita maxima × Cucurbita moschata mit starkem Wurzelsystem und Fon-0,1-Toleranz für Wassermelone, Melone und Gurke.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000001' AND `locale` = 'de';
UPDATE `product_i18n` SET `description` = 'LUCKY F1; parlak koyu yeşil rengi, 21-23 cm uzunluğunda düzgün ve pürüzsüz meyve yapısı ile yüksek pazar kalitesi sunan profesyonel çarliston biber çeşididir. Güz, tek ekim ve yayla yetiştiriciliğine uygundur. TSWV ve Tm 0-2 toleransı, orta-kalın meyve eti, yüksek soğuk performansı, uzun raf ömrü ve %100 tatlı lezzeti ile ticari üretimde öne çıkar.', `meta_description` = 'LUCKY F1 çarliston biber; 21-23 cm meyve boyu, TSWV ve Tm 0-2 toleransı, yüksek soğuk performansı ve %100 tatlı yapısıyla öne çıkar.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000002' AND `locale` = 'tr';
UPDATE `product_i18n` SET `description` = 'LUCKY F1 is a professional Charleston pepper variety with bright dark green color and a smooth, uniform fruit structure of 21-23 cm, offering high market quality. It is suitable for autumn, single-cycle and highland cultivation. TSWV and Tm 0-2 tolerance, medium-thick flesh, strong cold performance, long shelf life and 100% sweet taste make it a strong commercial choice.', `meta_description` = 'LUCKY F1 Charleston pepper offers 21-23 cm fruits, TSWV and Tm 0-2 tolerance, strong cold performance and a 100% sweet profile.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000002' AND `locale` = 'en';
UPDATE `product_i18n` SET `description` = 'LUCKY F1 ist eine professionelle Charleston-Paprikasorte mit glänzend dunkelgrüner Farbe und 21-23 cm langen, glatten und gleichmäßigen Früchten mit hoher Marktqualität. Sie eignet sich für Herbst-, Einmalsatz- und Hochlandanbau. TSWV- und Tm-0-2-Toleranz, mitteldickes Fruchtfleisch, hohe Kälteleistung, lange Haltbarkeit und ein zu 100 % süßes Aroma machen sie zu einer starken Wahl für den Erwerbsanbau.', `meta_description` = 'LUCKY F1 Charleston-Paprika bietet 21-23 cm Fruchtlänge, TSWV- und Tm-0-2-Toleranz, hohe Kälteleistung und ein zu 100 % süßes Profil.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000002' AND `locale` = 'de';
UPDATE `product_i18n` SET `description` = 'KIZGIN F1; sera ve açık tarla yetiştiriciliğine uygun, 23-25 cm meyve boyuna sahip profesyonel acı kıl biber çeşididir. Güçlü bitki yapısı, TSWV toleransı, ideal yeşil rengi, pürüzsüz düz şekli ve yüksek acılık oranı ile ticari üretimde güvenilir sonuç verir.', `meta_description` = 'KIZGIN F1 acı kıl biber; 23-25 cm meyve boyu, TSWV toleransı ve güçlü bitki yapısıyla sera ve açık tarla üretimine uygundur.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000003' AND `locale` = 'tr';
UPDATE `product_i18n` SET `description` = 'KIZGIN F1 is a professional hot thin pepper variety suitable for greenhouse and open-field cultivation, with a fruit length of 23-25 cm. Its strong plant structure, TSWV tolerance, ideal green color, smooth straight shape and high pungency deliver reliable commercial performance.', `meta_description` = 'KIZGIN F1 hot thin pepper offers 23-25 cm fruits, TSWV tolerance and strong plant vigor for greenhouse and open-field production.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000003' AND `locale` = 'en';
UPDATE `product_i18n` SET `description` = 'KIZGIN F1 ist eine professionelle scharfe dünne Paprikasorte für Gewächshaus- und Freilandanbau mit 23-25 cm Fruchtlänge. Die kräftige Pflanzenstruktur, TSWV-Toleranz, die ideale grüne Farbe, die glatte gerade Form und die hohe Schärfe sorgen für zuverlässige Ergebnisse im Erwerbsanbau.', `meta_description` = 'KIZGIN F1 scharfe dünne Paprika bietet 23-25 cm Früchte, TSWV-Toleranz und starke Pflanzenkraft für Gewächshaus- und Freilandproduktion.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000003' AND `locale` = 'de';
UPDATE `product_i18n` SET `description` = 'PRESTİJ F1; sera yetiştiriciliğine uygun, 22-24 cm meyve boyuna sahip güçlü yapıda profesyonel tatlı kıl biber çeşididir. Yüksek soğuk performansı ve TSWV toleransı ile zorlu koşullarda dahi verimliliğini korur. Düz, yeşil ve kılçıksız meyve yapısıyla pazar değeri yüksek çeşitler arasında yer alır.', `meta_description` = 'PRESTİJ F1 tatlı kıl biber; 22-24 cm meyve boyu, TSWV toleransı ve yüksek soğuk performansı ile sera yetiştiriciliği için uygundur.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000004' AND `locale` = 'tr';
UPDATE `product_i18n` SET `description` = 'PRESTIJ F1 is a professional sweet thin pepper variety with a strong plant structure and 22-24 cm fruits, suitable for greenhouse cultivation. Its high cold performance and TSWV tolerance help maintain productivity under challenging conditions. The straight, green and smooth fruit structure supports high market value.', `meta_description` = 'PRESTIJ F1 sweet thin pepper offers 22-24 cm fruits, TSWV tolerance and strong cold performance for greenhouse cultivation.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000004' AND `locale` = 'en';
UPDATE `product_i18n` SET `description` = 'PRESTIJ F1 ist eine professionelle süße dünne Paprikasorte mit kräftiger Pflanzenstruktur und 22-24 cm langen Früchten für den Gewächshausanbau. Hohe Kälteleistung und TSWV-Toleranz sichern die Produktivität auch unter anspruchsvollen Bedingungen. Die gerade, grüne und glatte Fruchtstruktur unterstützt einen hohen Marktwert.', `meta_description` = 'PRESTIJ F1 süße dünne Paprika bietet 22-24 cm Früchte, TSWV-Toleranz und hohe Kälteleistung für den Gewächshausanbau.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000004' AND `locale` = 'de';
UPDATE `product_i18n` SET `description` = 'BİRLİK F1; sera yetiştiriciliğine uygun, güçlü bitki yapısına sahip profesyonel kahvaltılık biber çeşididir. 16-18 cm boyunda, ince kabuklu ve parlak yeşil meyveleriyle yüksek pazar değeri sunar. Soğuk performansı ve TSWV ile Tm: 0-2 toleransı sayesinde üretim risklerini azaltır; erkenci yapısı ile kazancı destekler.', `meta_description` = 'BİRLİK F1 kahvaltılık biber; 16-18 cm meyve boyu, TSWV ve Tm: 0-2 toleransı, yüksek soğuk performansı ve erkenci yapısıyla öne çıkar.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000005' AND `locale` = 'tr';
UPDATE `product_i18n` SET `description` = 'BIRLIK F1 is a professional breakfast pepper variety suitable for greenhouse cultivation with a strong plant structure. Its 16-18 cm fruits are thin-skinned, bright green and highly marketable. Strong cold performance together with TSWV and Tm: 0-2 tolerance reduces risk, while its early habit supports higher returns.', `meta_description` = 'BIRLIK F1 breakfast pepper features 16-18 cm fruits, TSWV and Tm: 0-2 tolerance, strong cold performance and early maturity.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000005' AND `locale` = 'en';
UPDATE `product_i18n` SET `description` = 'BIRLIK F1 ist eine professionelle Frühstückspaprikasorte für den Gewächshausanbau mit kräftiger Pflanzenstruktur. Die 16-18 cm langen Früchte sind dünnschalig, glänzend grün und marktstark. Hohe Kälteleistung sowie TSWV- und Tm-0-2-Toleranz reduzieren das Produktionsrisiko, während die frühe Entwicklung den Ertrag unterstützt.', `meta_description` = 'BIRLIK F1 Frühstückspaprika bietet 16-18 cm Früchte, TSWV- und Tm-0-2-Toleranz, hohe Kälteleistung und frühe Reife.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000005' AND `locale` = 'de';
UPDATE `product_i18n` SET `description` = 'CANKAN F1; sera ve açık tarla üretimine uygun, güçlü bitki yapısına sahip profesyonel kapya biber çeşididir. 18-20 cm uzunluğundaki pürüzsüz ve koyu kırmızı meyveleriyle dikkat çeker. TSWV toleransı, yüksek uyum yeteneği ve %100 tatlı lezzeti sayesinde farklı iklim koşullarında güvenilir ticari performans sunar.', `meta_description` = 'CANKAN F1 kapya biber; 18-20 cm meyve boyu, TSWV toleransı, yüksek adaptasyon ve %100 tatlı lezzetiyle öne çıkar.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000006' AND `locale` = 'tr';
UPDATE `product_i18n` SET `description` = 'CANKAN F1 is a professional kapia pepper variety with strong plant structure, suitable for greenhouse and open-field production. Its 18-20 cm fruits are smooth, dark red and highly attractive. TSWV tolerance, high adaptability and a 100% sweet taste provide reliable commercial performance across different climates.', `meta_description` = 'CANKAN F1 kapia pepper offers 18-20 cm fruits, TSWV tolerance, high adaptability and a 100% sweet taste.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000006' AND `locale` = 'en';
UPDATE `product_i18n` SET `description` = 'CANKAN F1 ist eine professionelle Kapia-Paprikasorte mit kräftiger Pflanzenstruktur für Gewächshaus- und Freilandproduktion. Die 18-20 cm langen Früchte sind glatt, dunkelrot und markant. TSWV-Toleranz, hohe Anpassungsfähigkeit und ein zu 100 % süßer Geschmack sorgen für zuverlässige Ergebnisse in verschiedenen Klimazonen.', `meta_description` = 'CANKAN F1 Kapia-Paprika bietet 18-20 cm Früchte, TSWV-Toleranz, hohe Anpassungsfähigkeit und einen zu 100 % süßen Geschmack.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000006' AND `locale` = 'de';
UPDATE `product_i18n` SET `description` = 'TIRPAN F1; sera yetiştiriciliğine uygun, 19-21 cm boyunda koyu kırmızı ve %100 tatlı meyvelere sahip profesyonel kapya biber çeşididir. Yüksek sıcaklıklarda dahi güçlü meyve tutumu sağlar. Çatlama ve cracking yapmayan pürüzsüz meyve yapısı, TSWV toleransı ve yüksek adaptasyonu ile ticari üretimde güven verir.', `meta_description` = 'TIRPAN F1 kapya biber; 19-21 cm meyve boyu, TSWV toleransı, yüksek adaptasyon ve çatlama yapmayan kaliteli meyve yapısıyla öne çıkar.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000007' AND `locale` = 'tr';
UPDATE `product_i18n` SET `description` = 'TIRPAN F1 is a professional kapia pepper variety for greenhouse cultivation with 19-21 cm dark red fruits and a 100% sweet taste. It maintains strong fruit set even at high temperatures. Its smooth fruit structure resists cracking, while TSWV tolerance and high adaptability deliver confidence in commercial production.', `meta_description` = 'TIRPAN F1 kapia pepper offers 19-21 cm fruits, TSWV tolerance, high adaptability and crack-resistant fruit quality.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000007' AND `locale` = 'en';
UPDATE `product_i18n` SET `description` = 'TIRPAN F1 ist eine professionelle Kapia-Paprikasorte für den Gewächshausanbau mit 19-21 cm langen dunkelroten Früchten und zu 100 % süßem Geschmack. Auch bei hohen Temperaturen sorgt sie für starken Fruchtansatz. Die glatte, rissfeste Fruchtstruktur sowie TSWV-Toleranz und hohe Anpassungsfähigkeit schaffen Sicherheit im Erwerbsanbau.', `meta_description` = 'TIRPAN F1 Kapia-Paprika bietet 19-21 cm Früchte, TSWV-Toleranz, hohe Anpassungsfähigkeit und rissfeste Fruchtqualität.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000007' AND `locale` = 'de';
UPDATE `product_i18n` SET `description` = 'SARAY F1; sera ve açık tarla yetiştiriciliğine uygun, orta güçlü yapıda profesyonel dolma biber çeşididir. TSWV toleransı sayesinde hastalık baskısına karşı daha güvenlidir. 3-4 loblu, koyu yeşil ve kalın kabuklu meyveleri uzun raf ömrü ve yüksek nakliye dayanımı sağlayarak ticari değerini korur.', `meta_description` = 'SARAY F1 dolma biber; 3-4 loblu, koyu yeşil, kalın kabuklu meyve yapısı ve TSWV toleransı ile sera ve açık tarla üretimine uygundur.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000008' AND `locale` = 'tr';
UPDATE `product_i18n` SET `description` = 'SARAY F1 is a professional stuffing pepper variety with medium-strong plant structure, suitable for greenhouse and open-field cultivation. Its TSWV tolerance supports safer production under disease pressure. Dark green, thick-skinned fruits with 3-4 lobes offer long shelf life and strong transport durability for commercial trade.', `meta_description` = 'SARAY F1 stuffing pepper offers 3-4 lobed dark green fruits, thick skin and TSWV tolerance for greenhouse and open-field production.', `updated_at` = NOW(3) WHERE `product_id` = 'pppppppp-0001-4000-8000-000000000008' AND `locale` = 'en';
